async function populateCard(t,e){const a=await fetch(t),s=await a.json();for(const[t,a]of Object.entries(s.data)){const s=e.querySelectorAll(`.display_${t}`);for(const t of s)t&&(!0===a||!1===a?t.innerHTML=a?'<i class="fa fa-check text-success me-2"></i>Sim':'<i class="fa fa-times text-danger me-2"></i>Não':t.textContent=a??"")}return s}